import sys
import collections

def main():
    n, a, b = map(int, sys.stdin.readline().split())
    c = sys.stdin.readline().strip()
    c = [int(x) for x in c.split()]
    # print(n, a, b, c)
    count = collections.Counter(c)
    # print(count)
    if count[2] == 0:
        if c == c[::-1]:
            print(0)
        else:
            print(-1)
    else:
        if count[0] == 0:
            print(b * count[2])
        elif count[1] == 0:
            print(a * count[2])
        else:
            print(min(a * count[2], b * count[2]))


if __name__ == "__main__":
    main()
